+    let time: TimeInterval
+
+    var body: some View {
+        HStack(spacing: 4) {
+            ForEach(0..<3, id: \.self) { idx in
+                let phase = (time * 2 + Double(idx) * 0.45).truncatingRemainder(dividingBy: 1)
+                Circle()
+                    .fill(Color.white.opacity(0.75))
+                    .frame(width: 5, height: 5)
